"""هون رح تسالوا اكيد ليه ارجعت نظفت مره ثانيه رح احكيلكم لانه لما كنت بدي احسب السنوات الخبره الرموز الها معنى مثلا from 2010-2109 لو عملت ؤمثشى وشلت الرموز هيك رح يكون 2010 2019 وهيك بخرب الشغل مشان هيككككككك اوك"""

def clean_resume_text(txt):
    txt = re.sub(r'http\S+', ' ', txt)  # إزالة الروابط
    txt = re.sub(r'#\S+', ' ', txt)     # إزالة الهاشتاجات
    txt = re.sub(r'@\S+', ' ', txt)     # إزالة mentions
    txt = re.sub(r'[^\x00-\x7f]', ' ', txt)  # إزالة الأحرف الغريبة
    txt = re.sub(r'[!"#$%&\'()*+,-./:;<=>?@[\\]^_`{|}~]', ' ', txt) # إزالة الرموز
    txt = re.sub(r'\s+', ' ', txt)      # دمج المسافات
    return txt.strip().lower()

df_all['clean_resume'] = df_all['resume'].apply(clean_resume_text)

